    int *ptr = ___num;
    printf("Value: %d\n", ___ptr);
    return 0;
}

lessons.solution:
#include <stdio.h>
int main() {
    int num = 42;
    int *ptr = &num;
    printf("Value: %d\n", *ptr);
    return 0;
}

