    ___(fp, "C is fast");
    ___(fp);
    return 0;
}

lessons.solution:
#include <stdio.h>
int main() {
    FILE *fp = fopen("out.txt", "w");
    fprintf(fp, "C is fast");
    fclose(fp);
    return 0;
}

lessons.theory:
## Function Pointers
Pointers can point to functions, allowing you to pass them as callbacks.
```c
void hello() { printf("Hi"); }
void (*fn_ptr)() = hello;
fn_ptr();
```

lessons.starterCode:
#include <stdio.h>

int add(int a, int b) { return a + b; }

int main() {
    int (*op)(int, int) = ___;
    printf("Sum: %d\n", ___(2, 3));
    return 0;
}

lessons.solution:
#include <stdio.h>
int add(int a, int b) { return a + b; }
int main() {
    int (*op)(int, int) = add;
    printf("Sum: %d\n", op(2, 3));
    return 0;
}

